private boolean isEligibleForRetirementBenefits(Employee employee) {
    return employee.flags.contains(HOURLY)
        && employee.age > 65
        && !employee.isOnLeave();
}

UNIT_TEST_EXAMPLE:
@Test
public void isEligibleForRetirementBenefits_trueWhenAllConditionsMet() {
    Employee emp = new Employee(Set.of(HOURLY), 66, false);
    assertTrue(service.isEligibleForRetirementBenefits(emp));
}

@Test
public void isEligibleForRetirementBenefits_falseWhenOnLeave() {
    Employee emp = new Employee(Set.of(HOURLY), 66, true);
    assertFalse(service.isEligibleForRetirementBenefits(emp));
}
